mapper.select:
SELECT COUNT(1)
FROM user_songs
WHERE user_id = #{userId}
  AND song_id = #{songId}

mapper.update:
UPDATE user_songs
SET is_saved = 1
WHERE user_id = #{userId}
  AND song_id = #{songId}

UPDATE user_songs
SET rating = #{rating}
WHERE user_id = #{userId}
  AND song_id = #{songId}
  AND is_saved = 1

UPDATE user_songs
SET play_count = play_count + 1,
    last_played_at = NOW()
WHERE user_id = #{userId}
  AND song_id = #{songId}
  AND is_saved = 1

UPDATE user_songs
SET is_saved = 0
WHERE user_id = #{userId}
  AND song_id = #{songId}
  AND is_saved = 1
